import { useState, useEffect, useCallback, useRef } from 'react';
import { api } from '../utils/api';
import { prefetch } from '../utils/prefetch';

function normalizeRegions(data) {
  if (!data) return [];
  if (Array.isArray(data)) return data;
  const obj = data.regions || data;
  if (typeof obj === 'object' && !Array.isArray(obj)) {
    return Object.entries(obj).map(([key, val]) => ({
      ...val,
      region: key,
      name: val?.label || key,
      enabled: val?.enabled ?? true,
      currency: val?.currency || 'USD',
      cached_symbols: val?.cached_symbols || val?.symbol_count || 0,
      market_hours: typeof val?.market_hours === 'object'
        ? `${val.market_hours.open || ''}-${val.market_hours.close || ''}`
        : val?.market_hours || '--',
      timezone: val?.market_hours?.timezone || '--',
    }));
  }
  return [];
}

function mergeDataDepth(regions, depthData) {
  if (!depthData?.regions) return regions;
  const depthMap = {};
  for (const d of depthData.regions) {
    depthMap[d.region] = d;
  }
  return regions.map(r => {
    const depth = depthMap[r.region];
    if (!depth) return r;
    return {
      ...r,
      symbols: depth.symbols,
      disk_mb: depth.disk_mb,
      total_bars: depth.total_bars,
      avg_bars: depth.avg_bars,
      earliest: depth.earliest,
      latest: depth.latest,
    };
  });
}

export default function useSystemHealth() {
  // Seed from prefetch cache for instant first render
  const cachedHealth = prefetch.get('systemHealth');
  const [health, setHealth] = useState(cachedHealth || null);
  const [regions, setRegions] = useState([]);
  const [controlHealth, setControlHealth] = useState(null);
  const [cacheStatus, setCacheStatus] = useState(null);
  const [dataDepth, setDataDepth] = useState(null);
  const [sources, setSources] = useState(null);
  const [loading, setLoading] = useState(!cachedHealth);
  const [error, setError] = useState(null);
  const depthRef = useRef(null);

  const fetchAll = useCallback(async () => {
    try {
      const [healthData, regionsData, controlData, cacheData, sourcesData] = await Promise.all([
        api('/system/health'),
        api('/system/regions'),
        api('/control/health'),
        api('/data/cache/status'),
        api('/system/sources'),
      ]);

      if (healthData) setHealth(healthData);
      if (controlData) setControlHealth(controlData);
      if (cacheData) setCacheStatus(cacheData);
      if (sourcesData) setSources(sourcesData);
      if (regionsData) {
        const normalized = normalizeRegions(regionsData);
        setRegions(depthRef.current ? mergeDataDepth(normalized, depthRef.current) : normalized);
      }
      setError(null);
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
  }, []);

  const fetchDepth = useCallback(async () => {
    try {
      const depth = await api('/system/data-depth');
      if (depth) {
        depthRef.current = depth;
        setDataDepth(depth);
        setRegions(prev => mergeDataDepth(prev, depth));
      }
    } catch { /* non-critical */ }
  }, []);

  useEffect(() => {
    fetchAll();
    fetchDepth();
    const healthInterval = setInterval(fetchAll, 30000);   // was 15s, now 30s — halves API load
    const depthInterval = setInterval(fetchDepth, 120000); // was 60s, now 120s
    return () => {
      clearInterval(healthInterval);
      clearInterval(depthInterval);
    };
  }, [fetchAll, fetchDepth]);

  return { health, regions, controlHealth, cacheStatus, dataDepth, sources, loading, error };
}
